class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return False
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        return True

def solve(n: int, edges: list[list[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    uf = UnionFind(n)
    components = n
    max_cost = 0

    for u, v, w in edges:
        if components <= k:
            break
        if uf.union(u, v):
            components -= 1
            max_cost = max(max_cost, w)

    return max_cost
